                    : 'bg-white border border-slate-200 shadow-xl z-10 opacity-95 lg:scale-95'
                  }
                `}
              >

                {/* DOMINATION PACK HEADER */}
                {isDominationPack && (
                  <div className="bg-red-500/10 border-b border-red-500/20 py-3 px-4 flex items-center justify-center gap-2 text-red-400 text-sm font-bold uppercase tracking-wider animate-pulse">
                    <TrendingUp size={16} />
                    {plan.priceNote}
                  </div>
                )}

                {/* SUBSCRIPTION PACK HEADER */}
                {!isDominationPack && plan.discountLabel && (
                  <div className="bg-brand-blue text-white py-2 px-4 text-center text-sm font-bold uppercase tracking-wider">
                    {plan.discountLabel}
                  </div>
                )}

                <div className="p-8 sm:p-10 flex-grow flex flex-col">

                  <div className="text-center mb-8">
                    <h3 className={`text-xl font-black uppercase tracking-wide mb-4 ${isDominationPack ? 'text-brand-blue' : 'text-slate-800'}`}>
                      {plan.title}
                    </h3>

                    <div className="flex flex-col items-center justify-center mb-2">
                      {plan.originalPrice && (
                        <span className={`text-lg line-through font-bold decoration-2 mb-1 ${isDominationPack ? 'text-slate-500 decoration-red-500' : 'text-slate-400 decoration-red-500'}`}>
                          {plan.originalPrice}
                        </span>
                      )}
                      <div className={`text-6xl font-black tracking-tighter ${isDominationPack ? 'text-white' : 'text-slate-900'}`}>
                        {plan.price}
                      </div>
                      {!isDominationPack && <span className="text-sm font-bold text-slate-400 mt-1">HT</span>}
                    </div>

                    {isDominationPack && (
                      <div className="inline-block bg-slate-800 text-slate-300 text-xs font-bold px-3 py-1 rounded-full mt-2 border border-slate-700">
                        Paiement unique à vie
                      </div>
                    )}

                    <p className={`font-medium leading-relaxed mt-6 ${isDominationPack ? 'text-slate-400' : 'text-slate-500'}`}>
                      {plan.description}
                    </p>
                  </div>

                  {/* Features List */}
                  <div className={`rounded-2xl p-6 mb-8 ${isDominationPack ? 'bg-[#1E293B] border border-slate-700/50' : 'bg-slate-50 border border-slate-100'}`}>
                    <ul className="space-y-4">
                      {plan.features.map((feature, fIndex) => (
                        <li key={fIndex} className="flex items-start gap-3">
                          <div className={`mt-0.5 flex-shrink-0 w-5 h-5 rounded-full flex items-center justify-center ${isDominationPack ? 'bg-brand-blue/20 text-brand-blue' : 'bg-green-100 text-green-600'}`}>
                             <CheckCircle2 size={14} strokeWidth={3} />
                          </div>
                          <span className={`text-sm font-bold ${isDominationPack ? 'text-slate-200' : 'text-slate-700'}`}>
                            {feature}
                          </span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  {/* Bonuses Section (Yellow Box for Domination) */}
                  {plan.bonuses && plan.bonuses.length > 0 && (
