                         <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-brand-yellow text-brand-dark text-[10px] font-black uppercase px-3 py-1 rounded-full tracking-wider shadow-lg shadow-brand-yellow/20">
                            Bonus Offerts (Durée Limitée)
                         </div>
                      )}

                      <div className={`flex items-center gap-2 font-black uppercase text-xs tracking-wider mb-4 ${isDominationPack ? 'text-brand-yellow' : 'text-slate-400'}`}>
                        <Gift size={16} /> {!isDominationPack && "Cadeaux inclus"}
                      </div>

                      <ul className="space-y-3">
                        {plan.bonuses.map((bonus, bIndex) => (
                          <li key={bIndex} className="flex justify-between items-center gap-2 text-xs sm:text-sm">
                            <span className={`font-bold ${isDominationPack ? 'text-white' : 'text-slate-700'}`}>
                              {bonus.split('(')[0]}
                            </span>
                            <span className={`font-black text-[10px] uppercase px-2 py-0.5 rounded ${isDominationPack ? 'bg-brand-yellow text-brand-dark' : 'bg-green-100 text-green-700'}`}>
                              Offert
                            </span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}

                  <Button 
                    variant={isDominationPack ? 'secondary' : 'outline'}
                    className={`w-full justify-center py-4 text-lg font-bold rounded-xl shadow-xl transition-transform active:scale-95 ${
                      isDominationPack 
                        ? 'bg-white text-brand-dark hover:bg-brand-yellow hover:text-brand-dark border-none' 
                        : 'border-2'
                    }`}
                    onClick={() => document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' })}
                  >
                    {plan.buttonText} {isDominationPack && "⚡"}
                  </Button>

                  <p className={`text-center text-[10px] mt-4 font-medium ${isDominationPack ? 'text-slate-500' : 'text-slate-400'}`}>
                    {isDominationPack ? 'Offre limitée à 1 artisan par ville pour éviter la concurrence.' : 'Engagement 12 mois • Tacite reconduction'}
                  </p>

                </div>
              </div>
            );
          })}
        </div>

      </div>
    </section>
  );
};

export default Pricing;
