import React, { useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import Problem from './components/Problem';
import Stats from './components/Stats';
import Benefits from './components/Benefits';
import Process from './components/Process';
import Pricing from './components/Pricing';
import Testimonials from './components/Testimonials';
import Comparison from './components/Comparison';
import Portfolio from './components/Portfolio';
import FAQ from './components/FAQ';
import Contact from './components/Contact';
import Footer from './components/Footer';
import FloatingWhatsApp from './components/FloatingWhatsApp';

const App: React.FC = () => {

  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('active');
        }
      });
    }, { threshold: 0.1, rootMargin: "0px 0px -50px 0px" });

    const elements = document.querySelectorAll('.reveal');
    elements.forEach(el => observer.observe(el));

    return () => observer.disconnect();
  }, []);

  return (
    <div className="min-h-screen bg-white text-brand-dark font-sans selection:bg-brand-blue selection:text-white">
      <Header />
      <main>
        {/* 1. ATTENTION & AUTORITÉ */}
        <Hero />
        <Stats />

        {/* 2. PROBLÈME / AGITATION */}
        <Problem />

        {/* 3. DISQUALIFICATION DES CONCURRENTS (AUTORITÉ) */}
        <Comparison />

        {/* 4. SOLUTION & BÉNÉFICES (FUTUR RÊVÉ) */}
        <Benefits />

        {/* 5. MÉCANISME UNIQUE (COMMENT ÇA MARCHE) */}
        <Process />

        {/* 6. PREUVE SOCIALE & RÉSULTATS */}
        <Portfolio />
        <Testimonials />

        {/* 7. OFFRE IRRÉSISTIBLE & RARETÉ */}
        <Pricing />

        {/* 8. LEVÉE DES OBJECTIONS */}
        <FAQ />

        {/* 9. CTA FINAL */}
        <Contact />
      </main>
      <Footer />
      <FloatingWhatsApp />
    </div>
  );
};

export default App;
